mapper.select:
select * from bus_schedule

    
        and schedule_name like concat('%', #{query.scheduleName}, '%')
    
    
        and status = #{query.status}
    
    and create_user = #{userId}

ORDER BY create_time DESC

SELECT COUNT(schedule_id)
FROM bus_schedule
LEFT JOIN line ON bus_schedule.line_id = line.line_id

    
        and bus_schedule.schedule_name like concat('%', #{query.scheduleName}, '%')
    
    
        and bus_schedule.status = #{query.status}
    
    and bus_schedule.create_user = #{userId}

SELECT b.*, line.start_city, line.end_city, station.station_id, station.station_name, station.lng, station.lat, station.address FROM -- 核心：这里先把子查询【只查车次】，分页插件只会统计这里！ (SELECT DISTINCT bus_schedule.* FROM bus_schedule LEFT JOIN line ON bus_schedule.line_id = line.line_id
and bus_schedule.schedule_name like concat('%', #{query.scheduleName}, '%')
and bus_schedule.status = #{query.status}
and bus_schedule.create_user = #{userId}
) b
LEFT JOIN line ON b.line_id = line.line_id LEFT JOIN JSON_TABLE( line.station_list, '$[*]' COLUMNS ( station_id INT PATH '$', idx FOR ORDINALITY ) ) AS station_idx ON TRUE LEFT JOIN station ON station_idx.station_id = station.station_id
ORDER BY b.create_time DESC, station_idx.idx
